8.3 分散不均一のシミュレーション

simdata &lt;- function(N = 100) {
  x &lt;- rnorm(N, mean = 10, sd = 1)
  u &lt;- exp(x) * rnorm(N)
  y &lt;- 1 + x + u
  data.frame(x, y)
}

siml &lt;- do(1000) * {
  lm(y ~ x, data = simdata(100)) |&gt; tidy() |&gt;
    filter(term == "x") |&gt; select(estimate, std.error) |&gt;
    mutate(tval = (estimate - 1) / std.error)
}

通常の回帰分析を実施すると, 係数が不偏であっても, 正しく分散が推計できていないことが明らかである.

gf_dhistogram(~tval, data = siml) |&gt;
  gf_lims(x = c(-4, 4), y = c(0, 0.5)) |&gt;
  gf_dist("norm")








加重最小自乗法を実施したシミュレーションを実施する.

siml &lt;- do(1000) * {
  lm(y ~ x, data = simdata(100), weight = 1 / exp(x)) |&gt; tidy() |&gt;
    filter(term == "x") |&gt; select(estimate, std.error) |&gt;
    mutate(tval = (estimate - 1) / std.error)
}

加重最小自乗法を実施すると, 正規分布に近似できる.

gf_dhistogram(~tval, data = siml) |&gt;
  gf_lims(x = c(-4, 4), y = c(0, 0.5)) |&gt;
  gf_dist("norm")








ロバスト分散を利用したシミュレーションを実施する.

siml &lt;- do(1000) * {
  lm(y ~ x, data = simdata(100)) |&gt;
    coeftest(vcov = hccm) |&gt; tidy() |&gt;
    filter(term == "x") |&gt; select(estimate, std.error) |&gt;
    mutate(tval = (estimate - 1) / std.error)
}

ロバスト分散を利用した場合, 正規分布に近似できる.

gf_dhistogram(~tval, data = siml) |&gt;
  gf_lims(x = c(-4, 4), y = c(0, 0.5)) |&gt;
  gf_dist("norm")

9.2 シミュレーション
つぎのシミュレーションを考える.

simdata1 &lt;- function(N = 100) {
  z &lt;- rnorm(N, mean = 10, sd = 2)
  u &lt;- rnorm(N)
  x &lt;- z + u
  y &lt;- 1 + x + u
  data.frame(x, y, z)
}


siml_iv &lt;- do(500) *
  {
    df_sim &lt;- simdata1()
    df_ols &lt;- lm(y ~ x, data = df_sim) |&gt;
      tidy() |&gt;
      filter(term == "x") |&gt;
      select(estimate, std.error) |&gt;
      mutate(tval = (estimate - 1) / std.error)
    df_iv &lt;- ivreg(y ~ x | z, data = df_sim) |&gt;
      tidy() |&gt;
      filter(term == "x") |&gt;
      select(estimate, std.error) |&gt;
      rename(estimate_iv = estimate, std.error_iv = std.error) |&gt;
      mutate(tval_iv = (estimate_iv - 1) / std.error_iv)
    bind_cols(df_ols, df_iv)
  }


siml_iv |&gt;
  dplyr::select(estimate, estimate_iv) |&gt;
  tidyr::gather(variable, value) |&gt;
  favstats(~ value | variable, data = _)






最小二乗法による推定値のヒストグラムは以下である.

gf_histogram(~estimate, data = siml_iv) |&gt;
  gf_lims(x = c(0.5, 1.5)) |&gt;
  gf_vline(xintercept = 1)








操作変数法による推定値のヒストグラムは以下である.

gf_histogram(~estimate_iv, data = siml_iv) |&gt;
  gf_lims(x = c(0.5, 1.5)) |&gt;
  gf_vline(xintercept = 1)
